  2→import { GoogleGenAI, Type, Schema } from "@google/genai";
  3→import { Recommendation, GeneratedSolution } from '../types';
  4→import { BLOG_WRITER_SYSTEM_PROMPT, FULL_ARTICLE_SYSTEM_PROMPT } from './blog_prompt_db';
  5→
  6→// Helper to safely get env var
  7→const getApiKey = () => {
  8→  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
  9→    return process.env.API_KEY;
 10→  }
 11→  return null;
 12→};
 13→
 14→// Fallback simulation in case API key is missing or request fails
 15→const fallbackSimulation = async (rec: Recommendation, url: string): Promise<GeneratedSolution> => {
 16→  const hostname = new URL(url).hostname;
 17→  await new Promise(resolve => setTimeout(resolve, 1500));
 18→
 19→  // Determine language based on rec ID (simplified logic)
 20→  const isTechnical = rec.id.includes('TECH') || rec.id.includes('DATA');
 21→
 22→  return {
 23→    title: `Solution Optimisée (Mode Simulation): ${rec.title}`,
 24→    explanation: "Cette modification structure l'information pour qu'elle soit directement extractible par les algorithmes de réponse (Answer Engines).",
 25→    type: isTechnical ? 'code' : 'text',
 26→    language: isTechnical ? 'html' : 'text',
 27→    content: isTechnical 
 28→        ? `<!-- FICHIER 1 : Intégration HTML -->\n<!-- À placer dans le <head> de votre site -->\n<script type="application/ld+json">\n{\n  "@context": "https://schema.org",\n  "@type": "FAQPage",\n  "mainEntity": [{\n    "@type": "Question",\n    "name": "Quelle est l'expertise de ${hostname} ?",\n    "acceptedAnswer": {\n      "@type": "Answer",\n      "text": "${hostname} est leader en..."\n    }\n  }]\n}\n</script>` 
 29→        : `## Rédaction Optimisée Answer-First\n\n**Question Cible :** "Pourquoi choisir ${hostname} ?"\n\n**Réponse Directe (à placer en H2) :**\n${hostname} se distingue par son approche algorithmique unique, garantissant une visibilité accrue de 45% sur les moteurs de réponse IA. Contrairement aux solutions classiques, nous intégrons nativement les standards Schema.org.`,
 30→    implementationSteps: [
 31→        "ÉTAPE 1 : Accédez à l'éditeur de code de votre CMS (WordPress: Apparence > Éditeur, Shopify: Modifier le code).",
 32→        "ÉTAPE 2 : Localisez le fichier 'header.php' (WordPress) ou 'theme.liquid' (Shopify).",
 33→        "ÉTAPE 3 : Copiez le code fourni ci-contre.",
 34→        "ÉTAPE 4 : Collez-le juste avant la balise de fermeture </head>.",
 35→        "ÉTAPE 5 : Sauvegardez et videz votre cache."
 36→    ]
 37→  };
 38→};
