134→export const generateBlogArchitecture = async (topic: string, url: string): Promise<string> => {
135→  const apiKey = getApiKey();
136→  
137→  if (!apiKey) {
138→    // Simulation simple sans API Key
139→    await new Promise(resolve => setTimeout(resolve, 2000));
140→    return `# BRIEF DE RÉDACTION - [SIMULATION]\n\nCeci est une simulation car aucune clé API n'est détectée.\n\nSujet: ${topic}\nURL: ${url}\n\nPour obtenir un vrai résultat, veuillez configurer la clé API Gemini.`;
141→  }
142→
143→  try {
144→    const ai = new GoogleGenAI({ apiKey });
145→
146→    // Construction de la commande utilisateur basée sur les entrées
147→    let userCommand = "";
148→    if (url && topic) {
149→      userCommand = `Analyse l'URL ${url} et crée un nouvel article sur le sujet : ${topic}`;
150→    } else if (url) {
151→      userCommand = `Analyse l'URL ${url} et génère un brief d'amélioration`;
152→    } else {
153→      userCommand = `Crée une architecture d'article sur le thème : ${topic}`;
154→    }
155→
156→    const response = await ai.models.generateContent({
157→      model: 'gemini-2.5-flash',
158→      contents: userCommand,
159→      config: {
160→        systemInstruction: BLOG_WRITER_SYSTEM_PROMPT,
161→        temperature: 0.7,
162→      }
163→    });
164→
165→    return response.text || "# Erreur\nImpossible de générer le brief.";
166→
167→  } catch (error) {
168→    console.error("Blog Generation failed:", error); // TODO: Replace with proper error reporting (Sentry)
169→    return `# Erreur de génération\n\nUne erreur est survenue lors de l'appel à l'IA.\nDétails: ${error}`;
170→  }
171→};
