174→  const apiKey = getApiKey();
175→  
176→  if (!apiKey) {
177→    await new Promise(resolve => setTimeout(resolve, 2500));
178→    return `# Article Généré (Mode Simulation)\n\nCeci est une simulation de l'article complet car la clé API est manquante.\n\n## Introduction Optimisée\n\nLe sujet "${topic}" est crucial pour...\n\n(Veuillez configurer votre clé API pour la rédaction complète)`;
