184→    const userCommand = `Rédige l'article complet en suivant scrupuleusement le brief et le contexte fourni ci-dessous :\n\nCONTEXTE / SUJET : ${topic}\n\nBRIEF ET STRUCTURE À RESPECTER :\n${briefContent}`;
