 12→// ================================================================
 13→// URL PARSING HELPERS
 14→// ================================================================
 15→
 16→const parseUrl = (urlStr: string) => {
 17→  let hostname = urlStr;
 18→  let protocol = 'https';
 19→  let origin = `https://${urlStr}`;
 20→
 21→  try {
 22→    const urlObj = new URL(urlStr.startsWith('http') ? urlStr : `https://${urlStr}`);
 23→    hostname = urlObj.hostname;
 24→    protocol = urlObj.protocol.replace(':', '');
 25→    origin = urlObj.origin;
 26→  } catch (e) {
 27→    // Fallback
 28→  }
 29→
 30→  const cleanName = hostname.replace('www.', '').split('.')[0];
 31→  const entityName = cleanName.charAt(0).toUpperCase() + cleanName.slice(1);
 32→
 33→  // Simple platform detection
 34→  const lowerUrl = urlStr.toLowerCase();
 35→  let platform = 'Site General';
 36→  if (lowerUrl.includes('shopify') || lowerUrl.includes('store') || lowerUrl.includes('shop')) {
 37→    platform = 'Shopify / E-commerce';
 38→  } else if (lowerUrl.includes('wordpress') || lowerUrl.includes('blog') || lowerUrl.includes('wp-')) {
 39→    platform = 'WordPress';
 40→  } else if (lowerUrl.includes('app.') || lowerUrl.includes('dashboard') || lowerUrl.includes('portal')) {
 41→    platform = 'SaaS / Web App';
 42→  }
 43→
 44→  return { hostname, protocol, origin, entityName, platform };
 45→};
 46→
 47→// ================================================================
 48→// SYSTEM PROMPT — Combined expertise for all 6 tools
 49→// ================================================================
 50→
 51→const MEGA_SYSTEM_PROMPT = `
 52→# ROLE
 53→Tu es un Expert Senior multi-disciplinaire en AEO (Answer Engine Optimization) chez CitedBy.ai.
 54→Tu combines l'expertise de 6 specialites :
 55→1. Robots.txt Engineering (crawl budget, AI bots whitelist)
 56→2. Schema.org / JSON-LD (Knowledge Graph, rich results)
 57→3. llms.txt authoring (fichier texte pour guider les LLMs)
 58→4. llm.json authoring (carte d'identite machine-readable pour LLMs)
 59→5. Audit Answer-First (citabilite IA sur 6 criteres)
 60→6. Audit E-E-A-T (Experience, Expertise, Authoritativeness, Trustworthiness)
 61→
 62→# MISSION
 63→A partir d'une URL, genere en UNE SEULE reponse les 6 outputs pre-generes pour optimiser la visibilite IA du site.
 64→
 65→# REGLES GENERALES
 66→- Sois factuel, ne fabrique pas d'informations
 67→- Adapte chaque output au site analyse (nom, URL, plateforme)
 68→- Scores realistes (pas de 100/100 sauf justifie)
 69→- Reponds en francais pour les audits, en anglais pour les fichiers techniques (robots.txt, llms.txt, llm.json, schema.org)
 70→- Chaque section doit etre autonome et complete
 71→`;
 72→
 73→// ================================================================
 74→// RESPONSE SCHEMA
 75→// ================================================================
 76→
 77→const buildMegaSchema = (): Schema => {
 78→  const categorySchema: Schema = {
 79→    type: Type.OBJECT,
 80→    properties: {
 81→      score: { type: Type.NUMBER, description: "Score de 0 a 100" },
 82→      label: { type: Type.STRING, description: "Critique | Faible | Moyen | Bon | Excellent" },
 83→      details: { type: Type.STRING, description: "Explication 1-3 phrases" },
 84→      tips: { type: Type.ARRAY, items: { type: Type.STRING }, description: "2-5 conseils" },
 85→    },
 86→    required: ["score", "label", "details", "tips"],
 87→  };
 88→
 89→  const findingSchema: Schema = {
