105→      impact: { type: Type.NUMBER },
106→      effort: { type: Type.STRING },
107→      tool: { type: Type.STRING },
108→    },
109→    required: ["action", "impact", "effort", "tool"],
110→  };
111→
112→  return {
113→    type: Type.OBJECT,
114→    properties: {
115→      robotsTxt: {
116→        type: Type.OBJECT,
117→        properties: {
118→          content: { type: Type.STRING, description: "Contenu complet du fichier robots.txt" },
119→          platformDetected: { type: Type.STRING },
120→          aiBotsCount: { type: Type.NUMBER },
121→          rulesCount: { type: Type.NUMBER },
122→        },
123→        required: ["content", "platformDetected", "aiBotsCount", "rulesCount"],
124→      },
125→      schemaOrg: {
126→        type: Type.OBJECT,
127→        properties: {
128→          content: { type: Type.STRING, description: "JSON-LD Schema.org complet stringify" },
129→          typesCount: { type: Type.NUMBER },
130→          byteSize: { type: Type.NUMBER },
131→        },
132→        required: ["content", "typesCount", "byteSize"],
133→      },
134→      llmsTxt: {
135→        type: Type.OBJECT,
136→        properties: {
137→          content: { type: Type.STRING, description: "Fichier llms.txt complet en Markdown" },
138→          sections: { type: Type.NUMBER },
139→          wordCount: { type: Type.NUMBER },
140→        },
141→        required: ["content", "sections", "wordCount"],
142→      },
143→      llmJson: {
144→        type: Type.OBJECT,
145→        properties: {
146→          content: { type: Type.STRING, description: "Fichier llm.json complet stringify" },
147→          fieldCount: { type: Type.NUMBER },
148→          byteSize: { type: Type.NUMBER },
149→        },
150→        required: ["content", "fieldCount", "byteSize"],
151→      },
152→      answerFirstAudit: {
153→        type: Type.OBJECT,
154→        properties: {
155→          globalScore: { type: Type.NUMBER },
156→          summary: { type: Type.STRING },
157→          topRecommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
158→          categories: {
159→            type: Type.OBJECT,
160→            properties: {
161→              answerFirst: categorySchema,
162→              schemaOrg: categorySchema,
163→              faqStructure: categorySchema,
164→              semanticHtml: categorySchema,
165→              contentFreshness: categorySchema,
166→              metaOptimization: categorySchema,
167→            },
168→            required: ["answerFirst", "schemaOrg", "faqStructure", "semanticHtml", "contentFreshness", "metaOptimization"],
169→          },
170→        },
171→        required: ["globalScore", "summary", "topRecommendations", "categories"],
172→      },
173→      eeatAudit: {
174→        type: Type.OBJECT,
175→        properties: {
176→          scores: {
177→            type: Type.OBJECT,
178→            properties: {
