180→              experience: { type: Type.NUMBER },
181→              expertise: { type: Type.NUMBER },
182→              authoritativeness: { type: Type.NUMBER },
183→              trustworthiness: { type: Type.NUMBER },
184→            },
185→            required: ["overall", "experience", "expertise", "authoritativeness", "trustworthiness"],
186→          },
187→          findings: { type: Type.ARRAY, items: findingSchema },
188→          priorityActions: { type: Type.ARRAY, items: actionSchema },
189→          summary: { type: Type.STRING },
190→        },
191→        required: ["scores", "findings", "priorityActions", "summary"],
192→      },
193→    },
194→    required: ["robotsTxt", "schemaOrg", "llmsTxt", "llmJson", "answerFirstAudit", "eeatAudit"],
195→  };
196→};
