198→// ================================================================
199→// MAIN EXPORT
200→// ================================================================
201→
202→export interface MegaGenerationCache {
203→  robotsTxt: PreGeneratedSolutions['robotsTxt'];
204→  schemaOrg: PreGeneratedSolutions['schemaOrg'];
205→  llmsTxt: PreGeneratedSolutions['llmsTxt'];
206→  llmJson: PreGeneratedSolutions['llmJson'];
207→  answerFirstAudit: PreGeneratedSolutions['answerFirstAudit'];
208→  eeatAudit: PreGeneratedSolutions['eeatAudit'];
209→}
