211→export const megaGenerate = async (urlStr: string): Promise<MegaGenerationCache | null> => {
212→  const apiKey = getApiKey();
213→
214→  if (!apiKey) {
215→    console.warn("[MegaGenerator] API_KEY not found, skipping pre-generation.");
216→    return null;
217→  }
218→
219→  const { hostname, protocol, origin, entityName, platform } = parseUrl(urlStr);
220→
221→  try {
222→    const ai = new GoogleGenAI({ apiKey });
223→
224→    const userPrompt = `
225→SITE A ANALYSER :
226→- URL complete : ${urlStr}
227→- Hostname : ${hostname}
228→- Protocol : ${protocol}
229→- Origin : ${origin}
230→- Nom extrait : ${entityName}
231→- Plateforme detectee : ${platform}
232→- Description estimee : Site officiel de ${entityName}
233→- Contact estime : contact@${hostname}
234→
235→GENERE LES 6 OUTPUTS SUIVANTS :
236→
237→1. ROBOTS.TXT : Fichier robots.txt complet optimise AEO avec whitelist explicite de tous les bots IA (GPTBot, ChatGPT-User, Google-Extended, CCBot, ClaudeBot, anthropic-ai, Applebot, PerplexityBot, Amazonbot, FacebookBot, Bytespider, Cohere-ai, YouBot). Adapte les Disallow a la plateforme ${platform}. Inclus les Sitemaps. Format robots.txt standard (pas de JSON).
238→
239→2. SCHEMA.ORG : JSON-LD avec @graph contenant Organization (@id, name, url, logo, description, sameAs, contactPoint), WebSite (publisher, SearchAction), WebPage (isPartOf, about). Le champ content doit contenir le JSON-LD stringify.
240→
241→3. LLMS.TXT : Fichier llms.txt en Markdown avec H1 ${entityName}, blockquote description, sections About, Services, Key Pages, Contact, Instructions for AI. Format standard llms.txt.
242→
243→4. LLM.JSON : Fichier llm.json avec @context, entity, identity, authority, services, content_sources, citation_preferences, contact, ai_instructions, schema_org. Le champ content doit contenir le JSON stringify.
244→
245→5. AUDIT ANSWER-FIRST : Evaluation de la citabilite IA sur 6 categories (answerFirst 25%, schemaOrg 20%, faqStructure 15%, semanticHtml 15%, contentFreshness 10%, metaOptimization 15%). Scores realistes, globalScore = moyenne ponderee.
246→
247→6. AUDIT E-E-A-T : Evaluation E-E-A-T avec scores (overall, experience, expertise, authoritativeness, trustworthiness), findings (10-15 elements), priorityActions (5 max), summary.
248→    `;
249→
250→    const response = await ai.models.generateContent({
251→      model: 'gemini-2.5-flash',
252→      contents: userPrompt,
253→      config: {
254→        systemInstruction: MEGA_SYSTEM_PROMPT,
255→        responseMimeType: 'application/json',
256→        responseSchema: buildMegaSchema(),
257→        temperature: 0.3,
258→      },
259→    });
260→
261→    let output = response.text;
262→    if (!output) {
263→      throw new Error("Empty response from AI");
264→    }
265→
266→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
267→    const parsed = JSON.parse(output);
268→
269→    // Validate and build result — each section is individually validated
270→    const result: MegaGenerationCache = {
271→      robotsTxt: undefined,
272→      schemaOrg: undefined,
273→      llmsTxt: undefined,
274→      llmJson: undefined,
275→      answerFirstAudit: undefined,
276→      eeatAudit: undefined,
277→    };
278→
279→    // Robots.txt
280→    if (parsed.robotsTxt?.content) {
281→      result.robotsTxt = {
282→        content: parsed.robotsTxt.content,
283→        platformDetected: parsed.robotsTxt.platformDetected || platform,
284→        aiBotsCount: parsed.robotsTxt.aiBotsCount || 10,
285→        rulesCount: parsed.robotsTxt.rulesCount || 15,
286→      };
287→    }
288→
289→    // Schema.org
290→    if (parsed.schemaOrg?.content) {
291→      let schemaContent = parsed.schemaOrg.content;
292→      try {
293→        const innerJson = JSON.parse(schemaContent);
294→        schemaContent = JSON.stringify(innerJson, null, 2);
295→      } catch { /* keep as-is */ }
296→      result.schemaOrg = {
297→        content: schemaContent,
298→        typesCount: parsed.schemaOrg.typesCount || 3,
299→        byteSize: parsed.schemaOrg.byteSize || new TextEncoder().encode(schemaContent).length,
300→      };
301→    }
302→
303→    // llms.txt
304→    if (parsed.llmsTxt?.content) {
305→      result.llmsTxt = {
306→        content: parsed.llmsTxt.content,
307→        sections: parsed.llmsTxt.sections || (parsed.llmsTxt.content.match(/^##?\s/gm) || []).length,
308→        wordCount: parsed.llmsTxt.wordCount || parsed.llmsTxt.content.split(/\s+/).filter(Boolean).length,
309→      };
310→    }
311→
312→    // llm.json
313→    if (parsed.llmJson?.content) {
314→      let jsonContent = parsed.llmJson.content;
315→      try {
316→        const innerJson = JSON.parse(jsonContent);
317→        jsonContent = JSON.stringify(innerJson, null, 2);
318→      } catch { /* keep as-is */ }
319→      result.llmJson = {
320→        content: jsonContent,
321→        fieldCount: parsed.llmJson.fieldCount || 10,
322→        byteSize: parsed.llmJson.byteSize || new TextEncoder().encode(jsonContent).length,
323→      };
324→    }
325→
326→    // Answer-First Audit
327→    if (parsed.answerFirstAudit?.categories && parsed.answerFirstAudit?.globalScore != null) {
328→      result.answerFirstAudit = {
329→        globalScore: parsed.answerFirstAudit.globalScore,
330→        url: urlStr,
331→        categories: parsed.answerFirstAudit.categories,
332→        summary: parsed.answerFirstAudit.summary || '',
