198→const getApiKey = (): string | null => {
199→  // Check VITE_GEMINI_API_KEY first (Vite frontend env), then API_KEY
200→  const viteKey = import.meta.env.VITE_GEMINI_API_KEY;
201→  if (viteKey) return viteKey;
202→
203→  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
204→    return process.env.API_KEY;
205→  }
206→  return null;
207→};
