209→/**
210→ * Génère TOUTES les solutions en UN SEUL appel API.
211→ *
212→ * @param url - URL analysée
213→ * @param pageTitle - Titre de la page détecté par l'analyseur
214→ * @param pageContent - Contenu textuel extrait (sera tronqué à 3000 chars)
215→ * @param failedCriteria - Liste des critères échoués issus de l'audit
216→ * @param detectedProducts - Produits/services détectés sur la page
217→ * @param detectedBrand - Nom de marque détecté
218→ * @returns Toutes les solutions pré-générées
219→ */
220→export async function generateAllSolutions(
221→  url: string,
222→  pageTitle: string,
223→  pageContent: string,
224→  failedCriteria: Array<{ id: string; name: string; category: string; maxPoints: number }>,
225→  detectedProducts: string[] = [],
226→  detectedBrand: string = '',
227→  language: string = 'fr'
228→): Promise<SolutionMegaGenerationResult> {
229→
230→  const apiKey = getApiKey();
231→
232→  if (!apiKey) {
233→    console.warn('[SolutionMegaGenerator] No API key found, using fallback simulation.');
234→    return generateFallbackResult(url, failedCriteria);
235→  }
236→
237→  const prompt = buildMegaPrompt(
238→    url, pageTitle, pageContent,
239→    failedCriteria, detectedProducts, detectedBrand, language
240→  );
241→
242→  try {
243→    const ai = new GoogleGenAI({ apiKey });
244→
245→    const response = await ai.models.generateContent({
246→      model: 'gemini-2.0-flash',
247→      contents: prompt,
248→      config: {
249→        systemInstruction: MEGA_SYSTEM_PROMPT,
250→        maxOutputTokens: 16000, // On veut une réponse longue et complète
251→        temperature: 0.3,
252→        // Basse température = plus factuel et structuré
253→      },
254→    });
255→
256→    const text = response.text || '';
257→
258→    // Nettoyer le JSON (supprimer backticks markdown si présents)
259→    const cleanJson = text
260→      .replace(/```json\n?/g, '')
261→      .replace(/```\n?/g, '')
262→      .trim();
263→
264→    const parsed = JSON.parse(cleanJson);
265→
266→    // Valider et enrichir le résultat
267→    const result: SolutionMegaGenerationResult = {
268→      generatedAt: new Date().toISOString(),
269→      url,
270→      apiModel: 'gemini-2.0-flash',
271→      tokenCount: text.length, // approximation
272→
273→      solutions: (parsed.solutions || []).map((sol: Record<string, unknown>, index: number) => ({
274→        id: (sol.id as string) || `sol_${String(index + 1).padStart(3, '0')}`,
275→        category: (sol.category as string) || 'content',
276→        title: (sol.title as string) || `Solution ${index + 1}`,
277→        description: (sol.description as string) || '',
278→        priority: (sol.priority as string) || 'medium',
279→        estimatedImpact: (sol.estimatedImpact as number) || 2,
280→        fixesCriteria: (sol.fixesCriteria as string[]) || [],
281→        mostImpactedEngines: (sol.mostImpactedEngines as string[]) || [],
282→        generatedContent: {
283→          code: (sol.generatedContent as Record<string, unknown>)?.code as string || '',
284→          language: (sol.generatedContent as Record<string, unknown>)?.language as string || 'html',
285→          explanation: (sol.generatedContent as Record<string, unknown>)?.explanation as string || '',
286→          implementationSteps: (sol.generatedContent as Record<string, unknown>)?.implementationSteps as string[] || [],
287→        },
288→      })),
289→
290→      fullFAQ: parsed.fullFAQ || { html: '', schemaJsonLd: '', questionsCount: 0 },
291→      fullSchemaOrg: parsed.fullSchemaOrg || { jsonLd: '', types: [] },
292→      fullMetaTags: parsed.fullMetaTags || { title: '', description: '', openGraph: '', canonical: '' },
293→      fullIntroduction: parsed.fullIntroduction || { html: '', wordCount: 0 },
294→      fullComparativeTable: parsed.fullComparativeTable || { html: '', columnsCount: 0, rowsCount: 0 },
295→      fullArticleOutline: parsed.fullArticleOutline || { markdown: '', sections: [], estimatedWordCount: 0 },
296→
297→      solutionsCount: (parsed.solutions || []).length,
298→      totalEstimatedImpact: (parsed.solutions || []).reduce(
299→        (sum: number, s: Record<string, unknown>) => sum + ((s.estimatedImpact as number) || 0), 0
300→      ),
301→    };
302→
303→    return result;
304→
305→  } catch (error) {
306→    console.error('Erreur méga-génération solutions:', error);
307→    // Fallback : retourner un résultat simulé mais valide
308→    return generateFallbackResult(url, failedCriteria);
309→  }
310→}
