118→const detectPlatform = (url: string): PlatformConfig => {
119→  const lowerUrl = url.toLowerCase();
120→
121→  if (lowerUrl.includes('shopify') || lowerUrl.includes('store') || lowerUrl.includes('shop')) {
122→    return {
123→      name: 'Shopify / E-commerce',
124→      disallow: ['/cart', '/orders', '/checkouts', '/account', '/collections/*+*', '/blogs/*+*', '/*design_theme_id'],
125→      sitemaps: ['/sitemap.xml', '/sitemap_products_1.xml']
126→    };
127→  }
128→
129→  if (lowerUrl.includes('wordpress') || lowerUrl.includes('blog') || lowerUrl.includes('wp-')) {
130→    return {
131→      name: 'WordPress',
132→      disallow: ['/wp-admin/', '/wp-includes/', '/wp-content/plugins/', '/xmlrpc.php', '/readme.html', '/?s='],
133→      sitemaps: ['/sitemap_index.xml', '/post-sitemap.xml']
134→    };
135→  }
136→
137→  if (lowerUrl.includes('app.') || lowerUrl.includes('dashboard') || lowerUrl.includes('portal')) {
138→    return {
139→      name: 'SaaS / Web App',
140→      disallow: ['/api/', '/dashboard/', '/settings/', '/user/', '/private/', '/auth/'],
141→      sitemaps: ['/sitemap.xml']
142→    };
143→  }
144→
145→  // Default / Generic
146→  return {
147→    name: 'Site Général',
148→    disallow: ['/admin/', '/login/', '/tmp/', '/private/', '/search'],
149→    sitemaps: ['/sitemap.xml']
150→  };
151→};
