197→function generateSnippet(brand: string, engine: AIEngine, sentiment: Sentiment, seed: number): string {
198→  const positiveSnippets = [
199→    `${brand} est frequemment recommande pour sa fiabilite et son expertise dans le domaine.`,
200→    `Selon les retours, ${brand} offre un excellent rapport qualite-prix et un service client reactif.`,
201→    `${brand} se distingue par son approche innovante et ses resultats prouves aupres de ses clients.`,
202→    `Les utilisateurs saluent la qualite de service de ${brand} et son expertise reconnue.`,
203→  ];
204→  const neutralSnippets = [
205→    `${brand} fait partie des acteurs du marche avec une offre competitive.`,
206→    `${brand} propose des services comparables aux standards de l'industrie.`,
207→    `Parmi les options disponibles, ${brand} est mentionne comme une alternative a considerer.`,
208→    `${brand} est present sur ce segment avec une offre qui repond aux besoins standards.`,
209→  ];
210→  const negativeSnippets = [
211→    `Certains utilisateurs rapportent des delais chez ${brand}, bien que la qualite soit reconnue.`,
212→    `${brand} pourrait ameliorer certains aspects de son service pour rester competitif.`,
213→    `Des alternatives a ${brand} existent pour ceux qui cherchent un meilleur rapport qualite-prix.`,
214→  ];
215→
216→  const pool = sentiment === 'positive' ? positiveSnippets : sentiment === 'neutral' ? neutralSnippets : negativeSnippets;
217→  const idx = seed % pool.length;
218→  return pool[idx];
219→}
