  2→
  3→import type {
  4→  TrackedQuery, CitationCheck, AIEngineId,
  5→  CitationRate
  6→} from '../../types/v3-types';
  7→import { callAIEngine } from './citation-api-client';
  8→import { detectCitation } from './citation-detector';
  9→
 10→interface ProjectConfig {
 11→  projectId: string;
 12→  clientUrl: string;
 13→  clientBrand: string;
 14→  brandVariants: string[];
 15→  productKeywords: string[];
 16→  competitors: string[];
 17→}
 18→
 19→const ENGINES: AIEngineId[] = ['chatgpt', 'perplexity', 'gemini'];
 20→
 21→/**
 22→ * Vérifie les citations pour une liste de requêtes sur les 3 moteurs IA.
 23→ * Retourne les résultats bruts.
 24→ */
 25→export async function runCitationChecks(
 26→  queries: TrackedQuery[],
 27→  config: ProjectConfig,
 28→  onProgress?: (current: number, total: number) => void
 29→): Promise<CitationCheck[]> {
 30→  const results: CitationCheck[] = [];
 31→  const totalCalls = queries.reduce((sum, q) => sum + q.variations.length * ENGINES.length, 0);
 32→  let currentCall = 0;
 33→
 34→  for (const query of queries) {
 35→    for (const variation of query.variations) {
 36→      for (const engine of ENGINES) {
 37→        try {
 38→          // Appel API
 39→          const apiResult = await callAIEngine(engine, variation);
 40→
 41→          // Détection citation
 42→          const detection = detectCitation(
 43→            apiResult.responseText,
 44→            apiResult.sources,
 45→            {
 46→              clientUrl: config.clientUrl,
 47→              clientBrand: config.clientBrand,
 48→              brandVariants: config.brandVariants,
 49→              productKeywords: config.productKeywords,
 50→              competitors: config.competitors,
 51→            }
 52→          );
 53→
 54→          results.push({
 55→            id: crypto.randomUUID(),
 56→            projectId: config.projectId,
 57→            trackedQueryId: query.id,
 58→            engine,
 59→            promptSent: variation,
 60→            promptVariationIndex: query.variations.indexOf(variation),
 61→            responseText: apiResult.responseText,
 62→            responseSources: apiResult.sources,
 63→            detection,
 64→            apiModel: apiResult.model,
 65→            apiCostUsd: apiResult.estimatedCostUsd,
 66→            responseTimeMs: apiResult.responseTimeMs,
 67→            createdAt: new Date().toISOString(),
 68→          });
 69→
 70→          currentCall++;
 71→          onProgress?.(currentCall, totalCalls);
 72→
 73→          // Rate limiting
 74→          await delay(engine === 'perplexity' ? 500 : engine === 'chatgpt' ? 200 : 100);
 75→        } catch (error) {
 76→          console.error(`Erreur vérification ${engine} pour "${variation}":`, error);
 77→          currentCall++;
 78→          onProgress?.(currentCall, totalCalls);
 79→        }
 80→      }
 81→    }
 82→  }
 83→
 84→  return results;
 85→}
 86→
 87→/**
 88→ * Agrège les résultats de vérification en taux de citation par moteur.
 89→ */
 90→export function aggregateCitationRates(
 91→  checks: CitationCheck[]
 92→): Record<AIEngineId, CitationRate> {
 93→  const result = {} as Record<AIEngineId, CitationRate>;
 94→
 95→  for (const engine of ENGINES) {
 96→    const engineChecks = checks.filter(c => c.engine === engine);
 97→    const detected = engineChecks.filter(c =>
 98→      c.detection.urlExactMatch || c.detection.brandExactMatch || c.detection.urlInSource
 99→    );
100→
101→    const totalChecks = engineChecks.length;
102→    const citationsDetected = detected.length;
103→    const rate = totalChecks > 0 ? Math.round((citationsDetected / totalChecks) * 100) : 0;
104→    const avgScore = detected.length > 0
105→      ? Math.round(detected.reduce((s, c) => s + c.detection.citationScore, 0) / detected.length)
106→      : 0;
107→
108→    result[engine] = {
109→      engine,
110→      totalChecks,
111→      citationsDetected,
112→      citationRatePercent: rate,
113→      avgCitationScore: avgScore,
114→      confidence: totalChecks >= 10 ? 'high' : totalChecks >= 5 ? 'medium' : 'low',
115→      trend: 'stable',
116→      trendDelta: 0,
117→    };
118→  }
119→
120→  return result;
121→}
